  async getCfDashboardCacheEntry(db, cacheKey = "", options = {}) {
    const normalizedKey = String(cacheKey || "").trim();
    if (!normalizedKey || !db) return null;
    const ready = await this.ensureCfDashboardCacheTable(db);
    if (!ready) return null;
    const nowTimestamp = Math.max(0, Number(options.nowMs) || nowMs());
    const includeExpired = options.includeExpired === true;
    const sql = includeExpired
      ? `SELECT cache_key, zone_id, bucket_date, payload, version, cached_at, expires_at, updated_at
          FROM ${this.CF_DASH_CACHE_TABLE}
          WHERE cache_key = ?
          LIMIT 1`
      : `SELECT cache_key, zone_id, bucket_date, payload, version, cached_at, expires_at, updated_at
          FROM ${this.CF_DASH_CACHE_TABLE}
          WHERE cache_key = ? AND expires_at > ?
          LIMIT 1`;
    try {
      let statement = db.prepare(sql).bind(normalizedKey);
      if (!includeExpired) statement = db.prepare(sql).bind(normalizedKey, nowTimestamp);
      const row = await statement.first();
      if (!row?.payload) return null;
      let payload = null;
      try {
        payload = JSON.parse(String(row.payload || "{}"));
      } catch {
        return null;
      }
      return {
        cacheKey: normalizedKey,
        zoneId: String(row?.zone_id || row?.zoneId || ""),
        bucketDate: String(row?.bucket_date || row?.bucketDate || ""),
        payload: sanitizeDashboardSnapshotPayload(payload),
        version: Number(row?.version) || 0,
        cachedAt: Number(row?.cached_at ?? row?.cachedAt) || 0,
        expiresAt: Number(row?.expires_at ?? row?.expiresAt) || 0,
        updatedAt: Number(row?.updated_at ?? row?.updatedAt) || 0
      };
    } catch (error) {
      logRuntimeFailure("cf_dashboard_cache.read_failed", error, { cacheKey: normalizedKey });
      return null;
    }
  },
  async putCfDashboardCacheEntry(db, entry = {}) {
    if (!db) return null;
    const ready = await this.ensureCfDashboardCacheTable(db);
    if (!ready) return null;
    const cacheKey = String(entry?.cacheKey || "").trim();
    if (!cacheKey) return null;
    const zoneId = String(entry?.zoneId || "").trim() || "default";
    const bucketDate = String(entry?.bucketDate || "").trim() || "current";
    const version = Math.max(0, Number(entry?.version) || 0);
    const cachedAt = Math.max(0, Number(entry?.cachedAt) || nowMs());
    const expiresAt = Math.max(cachedAt, Number(entry?.expiresAt) || cachedAt);
    const updatedAt = Math.max(cachedAt, Number(entry?.updatedAt) || cachedAt);
    const payloadText = JSON.stringify(sanitizeDashboardSnapshotPayload(entry?.payload || {}));
    await db.prepare(`INSERT INTO ${this.CF_DASH_CACHE_TABLE} (
      cache_key, zone_id, bucket_date, payload, version, cached_at, expires_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(cache_key) DO UPDATE SET
      zone_id = excluded.zone_id,
      bucket_date = excluded.bucket_date,
      payload = excluded.payload,
      version = excluded.version,
      cached_at = excluded.cached_at,
      expires_at = excluded.expires_at,
      updated_at = excluded.updated_at`).bind(
      cacheKey,
      zoneId,
      bucketDate,
      payloadText,
      version,
      cachedAt,
      expiresAt,
      updatedAt
    ).run();
    return {
      cacheKey,
      zoneId,
      bucketDate,
      version,
      cachedAt,
      expiresAt,
      updatedAt
    };
  },
  async deleteCfDashboardCacheEntry(db, cacheKey = "") {
    const normalizedKey = String(cacheKey || "").trim();
    if (!normalizedKey || !db) return false;
    const ready = await this.ensureCfDashboardCacheTable(db);
    if (!ready) return false;
    try {
      await db.prepare(`DELETE FROM ${this.CF_DASH_CACHE_TABLE} WHERE cache_key = ?`).bind(normalizedKey).run();
      return true;
    } catch (error) {
      logRuntimeFailure("cf_dashboard_cache.delete_failed", error, { cacheKey: normalizedKey });
      return false;
    }
  },
  async invalidateDashboardSnapshotCacheForConfigChange(env, options = {}) {
    const db = options?.db || this.getDB(env);
    if (!db) return 0;
    const nowTimestamp = Math.max(0, Number(options.nowMs) || nowMs());
    const cacheKeys = new Set();
    for (const rawConfig of [options?.prevConfig, options?.nextConfig]) {
      if (!rawConfig || typeof rawConfig !== "object") continue;
      const config = sanitizeRuntimeConfig(rawConfig);
      const dayWindow = buildOffsetDayWindow(new Date(nowTimestamp), config.scheduleUtcOffsetMinutes);
      cacheKeys.add(makeCfDashCacheDbKey(config.cfZoneId, dayWindow.dateKey));
    }
    if (!cacheKeys.size) return 0;
    await withNonCriticalFallback(
      Promise.all([...cacheKeys].map(cacheKey => this.deleteCfDashboardCacheEntry(db, cacheKey))),
      "dashboard.cache_invalidate",
      { cacheKeys: [...cacheKeys] },
      null
    );
    return cacheKeys.size;
  },
