    const parts = [];
    const pushPart = (label, value) => {
      const text = String(value || "").trim();
      if (!text) return;
      parts.push(`${label}=${text}`);
    };
    pushPart("RouteKind", routeContextDiagnostics.routeKind);
    pushPart("RequestHost", routeContextDiagnostics.requestHost);
    pushPart("ConfiguredHost", routeContextDiagnostics.configuredHost);
    pushPart("ConfiguredLegacyHost", routeContextDiagnostics.configuredLegacyHost);
