      waitJoinMs: Math.max(0, Math.round(Number(options.waitJoinMs ?? failoverTelemetry.waitJoinMs) || 0)) || null,
      demotedTarget: String(options.demotedTarget || failoverTelemetry.demotedTarget || "").trim() || null,
