const FINAL_UI_HTML = UI_HTML;
const ADMIN_INLINE_STYLE_BLOCK_PATTERN = /<style(?:\s[^>]*)?>([\s\S]*?)<\/style>/gi;
let cachedAdminInlineStylesheetHeadHtml = "";

function buildAdminUnifiedFieldRadiusStylesheet() {
  return `<style>#app{--admin-unified-field-radius:14px}#app :is(input:not([type="checkbox"]):not([type="radio"]):not([type="range"]):not([type="file"]):not([type="color"]),select,textarea,[role="combobox"]){border-radius:var(--admin-unified-field-radius)!important}#app textarea{border-radius:calc(var(--admin-unified-field-radius) + 2px)!important}#app :is(input:not([type="checkbox"]):not([type="radio"]):not([type="range"]):not([type="file"]):not([type="color"]),select,textarea){overflow:hidden}</style>`;
}

function buildRuntimeAdminInlineStylesheetHeadHtml() {
  if (cachedAdminInlineStylesheetHeadHtml) return cachedAdminInlineStylesheetHeadHtml;
  const templateSource = resolveAdminHtmlTemplateSource();
  if (!templateSource) return "";
  const styleHtml = Array.from(templateSource.matchAll(ADMIN_INLINE_STYLE_BLOCK_PATTERN))
    .map((match) => `<style>${String(match[1] || "")}</style>`)
    .join("");
  cachedAdminInlineStylesheetHeadHtml = `${styleHtml}${buildAdminUnifiedFieldRadiusStylesheet()}`;
  return cachedAdminInlineStylesheetHeadHtml;
}
const SITE_FAVICON_SVG = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64">
  <defs>
    <linearGradient id="media-favicon-bg" x1="18%" y1="12%" x2="84%" y2="88%">
      <stop offset="0%" stop-color="#3b82f6"/>
      <stop offset="100%" stop-color="#4f46e5"/>
    </linearGradient>
    <radialGradient id="media-favicon-highlight" cx="28%" cy="20%" r="72%">
      <stop offset="0%" stop-color="#ffffff" stop-opacity="0.34"/>
      <stop offset="55%" stop-color="#ffffff" stop-opacity="0.08"/>
      <stop offset="100%" stop-color="#ffffff" stop-opacity="0"/>
    </radialGradient>
  </defs>
  <rect x="4" y="4" width="56" height="56" rx="15" fill="url(#media-favicon-bg)"/>
  <rect x="4" y="4" width="56" height="56" rx="15" fill="url(#media-favicon-highlight)"/>
  <rect x="4.75" y="4.75" width="54.5" height="54.5" rx="14.25" fill="none" stroke="#ffffff" stroke-opacity="0.12" stroke-width="1.5"/>
  <path d="M24 18h8v28h-8zM24 18h18v6H24zM24 29h14v6H24zM24 40h18v6H24z" fill="#ffffff"/>
</svg>`;

function renderFaviconResponse(method = "GET") {
  const headers = new Headers({
    "Content-Type": "image/svg+xml;charset=UTF-8",
    "Cache-Control": "public, max-age=86400, s-maxage=604800, immutable"
  });
  applySecurityHeaders(headers);
  return new Response(method === "HEAD" ? null : SITE_FAVICON_SVG, { headers });
}

const ADMIN_HTML_DYNAMIC_PLACEHOLDERS = Object.freeze([
  "__ADMIN_BOOTSTRAP_JSON__",
  "__INIT_HEALTH_BANNER__",
  "__ADMIN_APP_ROOT__"
]);
const ADMIN_HTML_VARIANT_ETAG = "";

function splitAdminHtmlTemplate(template = "") {
  const source = String(template || "");
  const parts = [];
  let cursor = 0;
  for (const placeholder of ADMIN_HTML_DYNAMIC_PLACEHOLDERS) {
    const index = source.indexOf(placeholder, cursor);
    if (index < 0) throw new Error(`missing admin html placeholder: ${placeholder}`);
    parts.push(source.slice(cursor, index));
    cursor = index + placeholder.length;
  }
  parts.push(source.slice(cursor));
  return parts;
}

function renderAdminHtmlTemplate(parts = [], replacements = {}) {
  let html = String(parts[0] || "");
  for (let index = 0; index < ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length; index += 1) {
    const placeholder = ADMIN_HTML_DYNAMIC_PLACEHOLDERS[index];
    html += String(replacements[placeholder] || "");
    html += String(parts[index + 1] || "");
  }
  return html;
}

function resolveAdminHtmlTemplateSource() {
  const html = String(FINAL_UI_HTML || "");
  if (html) return html;
  if (!Array.isArray(ADMIN_HTML_PARTS_PLAIN) || ADMIN_HTML_PARTS_PLAIN.length !== ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length + 1) {
    return "";
  }
  return renderAdminHtmlTemplate(
    ADMIN_HTML_PARTS_PLAIN,
    Object.fromEntries(ADMIN_HTML_DYNAMIC_PLACEHOLDERS.map((placeholder) => [placeholder, placeholder]))
  );
}

const ADMIN_HTML_PARTS_PLAIN = splitAdminHtmlTemplate(FINAL_UI_HTML);

const ADMIN_BOOTSTRAP_PLACEHOLDER = "__ADMIN_BOOTSTRAP_JSON__";
const ADMIN_INIT_HEALTH_BANNER_PLACEHOLDER = "__INIT_HEALTH_BANNER__";
const ADMIN_APP_ROOT_PLACEHOLDER = "__ADMIN_APP_ROOT__";
const ADMIN_APP_ROOT_HTML = '<div id="app" v-cloak></div>';
const ADMIN_HTML_CACHE_CONTROL = "public, max-age=300, s-maxage=600";
const ADMIN_HTML_CACHE_KEY_ORIGIN = "https://admin-shell-cache.invalid";

function buildAdminBootstrapPayload(env, initHealth = buildInitHealth(env)) {
  const adminPath = getAdminPath(env);
  return {
    adminPath,
    loginPath: getAdminLoginPath(env),
    initHealth,
    hostDomain: resolveConfiguredHost(env)
  };
}

function renderAdminHtmlShell(bootstrapJson = "{}", initHealthBannerHtml = "", appRootHtml = ADMIN_APP_ROOT_HTML) {
  if (!Array.isArray(ADMIN_HTML_PARTS_PLAIN) || ADMIN_HTML_PARTS_PLAIN.length !== ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length + 1) {
    return "";
  }
  return renderAdminHtmlTemplate(
    ADMIN_HTML_PARTS_PLAIN,
    {
      [ADMIN_BOOTSTRAP_PLACEHOLDER]: String(bootstrapJson || "{}"),
      [ADMIN_INIT_HEALTH_BANNER_PLACEHOLDER]: String(initHealthBannerHtml || ""),
      [ADMIN_APP_ROOT_PLACEHOLDER]: String(appRootHtml || ADMIN_APP_ROOT_HTML)
    }
  );
}

function buildAdminHtmlVariantEtag(bootstrap = {}, initHealth = null, appRootHtml = ADMIN_APP_ROOT_HTML) {
  const normalizedBootstrap = isPlainObject(bootstrap) ? bootstrap : {};
  const normalizedInitHealth = isPlainObject(initHealth)
    ? initHealth
    : (isPlainObject(normalizedBootstrap.initHealth) ? normalizedBootstrap.initHealth : {});
  const variantSignature = {
    templateRevision: String(ADMIN_HTML_VARIANT_ETAG || "").trim() || "admin-shell",
    adminPath: String(normalizedBootstrap.adminPath || "").trim(),
    loginPath: String(normalizedBootstrap.loginPath || "").trim(),
    hostDomain: normalizeHostnameText(normalizedBootstrap.hostDomain),
    initHealthOk: normalizedInitHealth.ok === true,
    initHealthMissing: normalizeDistinctConfigKeyList(normalizedInitHealth.missing),
    appRootHash: hashStableText(String(appRootHtml || ADMIN_APP_ROOT_HTML))
  };
  return `${variantSignature.templateRevision}-${hashStableText(serializeConfigValue(variantSignature))}`;
}

function formatAdminHtmlEtag(etag = "") {
  return `"${String(etag || "").trim()}"`;
}

function normalizeEtagToken(value = "") {
  return String(value || "").trim().replace(/^W\//i, "").replace(/^"(.*)"$/, "$1");
}

function requestHasMatchingEtag(request, currentEtag = "") {
  const ifNoneMatch = String(request?.headers?.get?.("If-None-Match") || "").trim();
  const normalizedCurrentEtag = normalizeEtagToken(currentEtag);
  if (!ifNoneMatch || !normalizedCurrentEtag) return false;
  return ifNoneMatch.split(",").some((token) => {
    const normalizedToken = normalizeEtagToken(token);
    return normalizedToken === "*" || normalizedToken === normalizedCurrentEtag;
  });
}

function buildAdminHtmlCacheKeyRequest(request, variantEtag = "") {
  const requestUrl = request instanceof Request ? new URL(request.url) : new URL(String(request || ""), ADMIN_HTML_CACHE_KEY_ORIGIN);
  const cacheUrl = new URL(requestUrl.pathname, ADMIN_HTML_CACHE_KEY_ORIGIN);
  cacheUrl.searchParams.set("variant", String(variantEtag || ""));
  return new Request(cacheUrl.toString(), { method: "GET" });
}

function buildAdminHtmlResponseHeaders(etag = "", cacheControl = "no-store, max-age=0") {
  const headers = new Headers({
    "Content-Type": "text/html;charset=UTF-8",
    "Cache-Control": String(cacheControl || "no-store, max-age=0")
  });
  applySecurityHeaders(headers);
  if (etag) headers.set("ETag", formatAdminHtmlEtag(etag));
  return headers;
}

function buildAdminNotModifiedResponse(etag = "", cacheControl = ADMIN_HTML_CACHE_CONTROL) {
  const headers = buildAdminHtmlResponseHeaders(etag, cacheControl);
  headers.delete("Content-Type");
  return new Response(null, { status: 304, headers });
}

function buildAdminHeadResponseFrom(response) {
  if (!response) return new Response(null, { status: 500 });
  return new Response(null, {
    status: response.status,
    statusText: response.statusText,
    headers: new Headers(response.headers)
  });
}

async function renderAdminPage(request, env, ctx, initHealth = buildInitHealth(env)) {
  const bootstrap = buildAdminBootstrapPayload(env, initHealth);
  const bootstrapJson = serializeInlineJson(bootstrap);
  const initHealthBannerHtml = buildInitHealthBannerHtml(initHealth);
  const appRootHtml = ADMIN_APP_ROOT_HTML;
  const isHealthyShell = initHealth?.ok === true;

  if (!isHealthyShell) {
    const html = renderAdminHtmlShell(bootstrapJson, initHealthBannerHtml, appRootHtml);
    return new Response(
      request?.method === "HEAD" ? null : html,
      { headers: buildAdminHtmlResponseHeaders("", "no-store, max-age=0") }
    );
  }

  const variantEtag = buildAdminHtmlVariantEtag(bootstrap, initHealth, appRootHtml);
  if (requestHasMatchingEtag(request, variantEtag)) {
    return buildAdminNotModifiedResponse(variantEtag, ADMIN_HTML_CACHE_CONTROL);
  }

  const cacheKey = buildAdminHtmlCacheKeyRequest(request, variantEtag);
  const edgeCache = typeof caches === "undefined" ? null : caches.default;
  if (edgeCache && typeof edgeCache.match === "function") {
    const cachedResponse = await edgeCache.match(cacheKey);
    if (cachedResponse) {
      return request?.method === "HEAD"
        ? buildAdminHeadResponseFrom(cachedResponse)
        : cachedResponse;
    }
  }

  const html = renderAdminHtmlShell(bootstrapJson, initHealthBannerHtml, appRootHtml);
  const headers = buildAdminHtmlResponseHeaders(variantEtag, ADMIN_HTML_CACHE_CONTROL);
  const cacheableResponse = new Response(html, { headers });
  if (edgeCache && typeof edgeCache.put === "function") {
    const cacheWriteTask = withNonCriticalFallback(
      edgeCache.put(cacheKey, cacheableResponse.clone()),
      "admin.shell_cache_write",
      { path: new URL(request.url).pathname, variantEtag },
      null
    );
    if (ctx && typeof ctx.waitUntil === "function") ctx.waitUntil(cacheWriteTask);
    else await cacheWriteTask;
  }
  return request?.method === "HEAD"
    ? buildAdminHeadResponseFrom(cacheableResponse)
    : cacheableResponse;
}

function renderLandingPage(env, initHealth = buildInitHealth(env)) {
  const adminPath = getAdminPath(env);
  const initBanner = initHealth.ok
    ? ''
    : `<div class="mb-4 rounded-2xl border border-amber-300/40 bg-amber-500/10 px-4 py-3 text-left text-amber-100"><div class="text-sm font-semibold">系统未初始化</div><div class="mt-1 text-xs leading-5 text-amber-50/90">缺少关键环境变量：${initHealth.missing.map(item => escapeHtml(item)).join('、')}</div></div>`;
  const html = `<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><link rel="icon" href="/favicon.ico" sizes="any"><title>Emby Proxy V19.2</title>${buildRuntimeAdminInlineStylesheetHeadHtml()}</head><body class="bg-slate-950 text-slate-100 min-h-screen"><main class="min-h-screen flex items-center justify-center px-6 py-12"><section class="max-w-3xl w-full rounded-[32px] border border-slate-800 bg-slate-900/95 shadow-2xl overflow-hidden"><div class="grid gap-0 md:grid-cols-[1.1fr,0.9fr]"><div class="p-8 md:p-10 text-left">${initBanner}<div class="inline-flex items-center rounded-full border border-brand-500/30 bg-brand-500/10 px-3 py-1 text-xs font-semibold tracking-[0.16em] uppercase text-brand-300">Headless Edge Relay</div><h1 class="mt-5 text-3xl md:text-4xl font-bold text-white leading-tight">Emby Proxy V19.2</h1><p class="mt-4 text-sm md:text-base leading-7 text-slate-300">为了极致优化视频代理的性能，当前根路径默认只保留一个无头（Headless）数据中继站；真正的管理界面、节点控制和 DNS 运维都收敛到单独的管理台入口。</p><p class="mt-3 text-sm md:text-base leading-7 text-slate-400">如果你现在需要配置节点、查看运行状态或调整 Cloudflare 相关参数，请直接访问 <span class="font-semibold text-white">${escapeHtml(adminPath)}</span>。</p><div class="mt-8 flex flex-col sm:flex-row gap-3"><a href="${escapeHtml(adminPath)}" class="inline-flex items-center justify-center rounded-2xl border border-brand-400/70 bg-brand-600 px-5 py-3 text-sm font-semibold text-white shadow-sm shadow-brand-950/20 transition hover:border-brand-300 hover:bg-brand-700">访问 ${escapeHtml(adminPath)}</a><a href="https://github.com/axuitomo/CF-EMBY-PROXY-UI" target="_blank" rel="noopener noreferrer" class="inline-flex items-center justify-center rounded-2xl border border-slate-700 px-5 py-3 text-sm font-semibold text-slate-200 hover:bg-slate-800 transition">查看项目说明</a></div></div><div class="border-t md:border-t-0 md:border-l border-slate-800 bg-slate-950/80 p-8 md:p-10 text-left"><div class="rounded-3xl border border-slate-800 bg-slate-900/70 p-6"><div class="text-xs font-semibold tracking-[0.16em] uppercase text-slate-500">Routing Notes</div><ul class="mt-4 space-y-3 text-sm leading-6 text-slate-300"><li>• 根路径仅提供静态说明页，不承载实时配置数据。</li><li>• \`${escapeHtml(adminPath)}\` 下发 SaaS 控制台骨架，动态数据继续走 \`POST ${escapeHtml(adminPath)}\` API。</li><li>• 媒体代理、日志与 KV / D1 逻辑保持原 Worker 主链路不变。</li></ul></div></div></div></section></main></body></html>`;
  const headers = new Headers({ 'Content-Type': 'text/html;charset=UTF-8', 'Cache-Control': 'public, max-age=3600, s-maxage=86400' });
  applySecurityHeaders(headers);
  headers.set('X-Frame-Options', 'DENY');
  return new Response(html, { headers });
}

function buildEdgeCorsResponse(dynamicCors, body, status = 200, options = {}) {
  const headers = new Headers(dynamicCors);
  applySecurityHeaders(headers);
  if (options.mergeOriginVary === true && headers.get("Access-Control-Allow-Origin") !== "*") {
    mergeVaryHeader(headers, "Origin");
  }
  return new Response(body, { status, headers });
}

const RuntimeEntry = {
  isLegacyAdminLoginRoute(routeContext) {
    return routeContext.adminPathLower === "/admin"
      && routeContext.pathnameLower === "/api/auth/login"
      && routeContext.root === "api"
      && routeContext.segments[1] === "auth"
      && routeContext.segments[2] === "login";
  },

  isAdminPreflightRoute(routeContext) {
    return pathnameMatchesPrefix(routeContext.pathnameLower, routeContext.adminPathLower)
      || pathnameMatchesExactOrTrailingSlash(routeContext.pathnameLower, routeContext.adminLoginPathLower)
      || RuntimeEntry.isLegacyAdminLoginRoute(routeContext);
  },

  buildFetchRouteContext(request, env) {
    const initHealth = warnInitHealthOnce(env);
    const dynamicCors = getCorsHeadersForResponse(env, request);
    const requestUrl = new URL(request.url);
    const requestHost = normalizeHostnameText(requestUrl.hostname);
    const normalizedPathname = sanitizeProxyPath(requestUrl.pathname);
    const pathnameLower = normalizedPathname.toLowerCase();
    const adminPath = getAdminPath(env);
    const adminPathLower = adminPath.toLowerCase();
    const adminLoginPath = getAdminLoginPath(env);
    const adminLoginPathLower = adminLoginPath.toLowerCase();
    const segments = normalizedPathname.split("/").filter(Boolean);
    const rootRaw = segments[0] || "";
    const root = safeDecodeSegment(rootRaw).toLowerCase();
    return {
      initHealth,
      dynamicCors,
      requestUrl,
      requestHost,
      requestHostLower: requestHost.toLowerCase(),
      configuredHost: resolveConfiguredHost(env),
      configuredLegacyHost: resolveConfiguredLegacyHost(env),
      normalizedPathname,
      pathnameLower,
      adminPath,
      adminPathLower,
      adminLoginPath,
      adminLoginPathLower,
      segments,
      rootRaw,
      root
    };
  },

  buildTrailingSlashRedirectResponse(request, normalizedPathname) {
    const redirectUrl = new URL(request.url);
    redirectUrl.pathname = normalizedPathname + "/";
    const headers = new Headers({ Location: redirectUrl.toString(), "Cache-Control": "no-store" });
    applySecurityHeaders(headers);
    const redirectStatus = (request.method === "GET" || request.method === "HEAD") ? 301 : 307;
    return new Response(null, { status: redirectStatus, headers });
  },

  buildCanonicalHostRedirectResponse(request, targetHost) {
    const normalizedTargetHost = normalizeHostnameText(targetHost);
    if (!normalizedTargetHost) return null;
    const redirectUrl = new URL(request.url);
    redirectUrl.hostname = normalizedTargetHost;
    const headers = new Headers({ Location: redirectUrl.toString(), "Cache-Control": "no-store" });
    applySecurityHeaders(headers);
    return new Response(null, { status: 301, headers });
  },

  appendSetCookieHeader(response, setCookieValue = "") {
    const normalizedSetCookieValue = String(setCookieValue || "").trim();
    if (!response || !normalizedSetCookieValue || response.status === 101) return response;
    const headers = new Headers(response.headers || {});
    headers.append("Set-Cookie", normalizedSetCookieValue);
    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers
    });
  },

  buildLegacyProxyContextNotFoundResponse(routeContext) {
    const response = buildEdgeCorsResponse(routeContext.dynamicCors, "Not Found", 404, { mergeOriginVary: true });
    return this.appendSetCookieHeader(response, buildLegacyProxyContextClearCookie());
  },

  async maybeAttachLegacyProxyContextResponse(response, requestHost, nodeName, env) {
    if (!response || response.status === 101) return response;
    const cookieValue = await buildLegacyProxyContextCookieValue(nodeName, requestHost, env);
    if (!cookieValue) return response;
    return this.appendSetCookieHeader(response, buildLegacyProxyContextSetCookie(cookieValue));
  },

  isPlaybackCriticalRouteContext(routeContext) {
    const segments = routeContext.segments;
    const buildCandidatePath = (startIndex = 1) => {
      const nextSegments = segments.slice(startIndex).map(item => safeDecodeSegment(item));
      if (nextSegments.length && parseProxyLinkVariantSegment(nextSegments[0]) !== "main") nextSegments.shift();
      return "/" + nextSegments.join("/");
    };
    if (segments.length <= 1) return false;
    if (isPlaybackCriticalProxyPath(buildCandidatePath(1))) return true;
    if (segments.length <= 2) return false;
    return isPlaybackCriticalProxyPath(buildCandidatePath(2));
  },

  async resolveProxyRouteContext(routeContext, env, ctx, request) {
    if (!routeContext.root) return null;
    const playbackHotEligible = RuntimeEntry.isPlaybackCriticalRouteContext(routeContext);
    let playbackRouteHotSnapshot = playbackHotEligible ? await Database.getVerifiedPlaybackRouteHotSnapshot(routeContext.root, env) : null;
    const targetHotCacheState = playbackHotEligible
      ? (playbackRouteHotSnapshot ? "hit" : "miss")
      : "skip";
    const nodeData = playbackRouteHotSnapshot?.nodeData || await Database.getNode(routeContext.root, env, ctx);
    if (!nodeData) return null;
    if (isHostPrefixEntryMode(nodeData?.entryMode)) return null;

    const secret = nodeData.secret;
    const routePrefix = buildProxyPrefix(routeContext.root, secret);
    const rootPrefixLen = 1 + routeContext.rootRaw.length;
    const rawPathAfterRoot = routeContext.normalizedPathname.substring(rootPrefixLen);
    const pathNormalizationState = tryNormalizeEmbeddedSameOriginPlaybackProxyPath(
      rawPathAfterRoot,
      routeContext.requestUrl,
      routePrefix
    );
    const normalizedPathAfterRoot = pathNormalizationState?.normalizedPath || rawPathAfterRoot;
    const normalizedPathname = `/${routeContext.rootRaw}${normalizedPathAfterRoot === "/" ? "/" : normalizedPathAfterRoot}`;
    const normalizedSegments = normalizedPathname.split("/").filter(Boolean);
    let prefixLen = rootPrefixLen;
    if (secret) {
      const secretRaw = normalizedSegments[1] || "";
      if (safeDecodeSegment(secretRaw) !== secret) return null;
      prefixLen += 1 + secretRaw.length;
    }

    const normalizedRemainingInput = normalizedPathname.substring(prefixLen);
    const normalizedRequestUrl = pathNormalizationState
      ? (() => {
          const nextUrl = new URL(routeContext.requestUrl.toString());
          nextUrl.pathname = normalizedPathname;
          return nextUrl;
        })()
      : routeContext.requestUrl;
    const linkVariantState = consumeProxyLinkVariantPrefix(normalizedRemainingInput);
    let remaining = linkVariantState.remaining;
    if ((normalizedRemainingInput === "" && !normalizedRequestUrl.pathname.endsWith("/")) || linkVariantState.needsTrailingSlashRedirect === true) {
      return {
        response: RuntimeEntry.buildTrailingSlashRedirectResponse(request, normalizedPathname)
      };
    }
    if (remaining === "") remaining = "/";
    if (playbackHotEligible && !playbackRouteHotSnapshot) {
      playbackRouteHotSnapshot = await Database.primePlaybackRouteHotSnapshot(routeContext.root, nodeData, env);
    }
    return {
      nodeData,
      secret,
      remaining: sanitizeProxyPath(remaining),
      linkVariant: linkVariantState.linkVariant,
      requestUrl: normalizedRequestUrl,
      pathNormalizationState,
      playbackRouteHotSnapshot,
      targetHotCacheState,
      entryMode: "kv_route"
    };
  },

  isHostPrefixPlaybackCriticalRouteContext(routeContext) {
    if (!routeContext) return false;
    const linkVariantState = consumeProxyLinkVariantPrefix(routeContext.normalizedPathname);
    const remaining = linkVariantState?.remaining || "/";
    return isPlaybackCriticalProxyPath(remaining);
  },

  async resolveHostPrefixProxyRouteContext(routeContext, env, ctx, request) {
    const hostPrefixMatch = routeContext?.hostPrefixMatch;
    if (!hostPrefixMatch?.prefix) return null;
    const nodeName = String(hostPrefixMatch.prefix || "").trim().toLowerCase();
    if (!nodeName) return null;
    const playbackHotEligible = RuntimeEntry.isHostPrefixPlaybackCriticalRouteContext(routeContext);
    let playbackRouteHotSnapshot = playbackHotEligible ? await Database.getVerifiedPlaybackRouteHotSnapshot(nodeName, env) : null;
    const targetHotCacheState = playbackHotEligible
      ? (playbackRouteHotSnapshot ? "hit" : "miss")
      : "skip";
    const nodeData = playbackRouteHotSnapshot?.nodeData || await Database.getNode(nodeName, env, ctx);
    if (!nodeData || !isHostPrefixEntryMode(nodeData?.entryMode)) return null;

    const linkVariantState = consumeProxyLinkVariantPrefix(routeContext.normalizedPathname);
    let remaining = linkVariantState.remaining;
    if (linkVariantState.needsTrailingSlashRedirect === true) {
      return {
        response: RuntimeEntry.buildTrailingSlashRedirectResponse(request, routeContext.normalizedPathname)
      };
    }
    if (remaining === "") remaining = "/";
    if (playbackHotEligible && !playbackRouteHotSnapshot) {
      playbackRouteHotSnapshot = await Database.primePlaybackRouteHotSnapshot(nodeName, nodeData, env);
    }
    return {
      nodeData,
      secret: "",
      remaining: sanitizeProxyPath(remaining),
      linkVariant: linkVariantState.linkVariant,
      requestUrl: routeContext.requestUrl,
      playbackRouteHotSnapshot,
      targetHotCacheState,
      entryMode: "host_prefix"
    };
  },

  isHostPrefixPathCompatHostRequest(routeContext) {
    const requestHost = String(routeContext?.requestHostLower || "").trim().toLowerCase();
    const configuredHost = String(routeContext?.configuredHost || "").trim().toLowerCase();
    const configuredLegacyHost = String(routeContext?.configuredLegacyHost || "").trim().toLowerCase();
    if (!requestHost) return false;
    if (configuredHost && requestHost === configuredHost) return true;
    return !!(
      configuredLegacyHost
      && configuredLegacyHost !== configuredHost
      && requestHost === configuredLegacyHost
    );
  },

  async resolveHostPrefixPathCompatRouteContext(routeContext, env, ctx, request, options = {}) {
    if (!this.isHostPrefixPathCompatHostRequest(routeContext) || !routeContext?.root) return null;
    const nodeName = String(routeContext.root || "").trim().toLowerCase();
    if (!nodeName) return null;

    const playbackHotEligible = RuntimeEntry.isPlaybackCriticalRouteContext(routeContext);
    let playbackRouteHotSnapshot = playbackHotEligible ? await Database.getVerifiedPlaybackRouteHotSnapshot(nodeName, env) : null;
    const targetHotCacheState = playbackHotEligible
      ? (playbackRouteHotSnapshot ? "hit" : "miss")
      : "skip";
    const nodeData = playbackRouteHotSnapshot?.nodeData || await Database.getNode(nodeName, env, ctx);
    if (!nodeData || !isHostPrefixEntryMode(nodeData?.entryMode)) return null;

    const routePrefix = buildProxyPrefix(nodeName, "", { entryMode: "kv_route" });
    const rootPrefixLen = 1 + routeContext.rootRaw.length;
    const rawPathAfterRoot = routeContext.normalizedPathname.substring(rootPrefixLen);
    const pathNormalizationState = tryNormalizeEmbeddedSameOriginPlaybackProxyPath(
      rawPathAfterRoot,
      routeContext.requestUrl,
      routePrefix
    );
    const normalizedPathAfterRoot = pathNormalizationState?.normalizedPath || rawPathAfterRoot;
    const normalizedPathname = `/${routeContext.rootRaw}${normalizedPathAfterRoot === "/" ? "/" : normalizedPathAfterRoot}`;
    const normalizedRemainingInput = normalizedPathname.substring(rootPrefixLen);
    const normalizedRequestUrl = pathNormalizationState
      ? (() => {
          const nextUrl = new URL(routeContext.requestUrl.toString());
          nextUrl.pathname = normalizedPathname;
          return nextUrl;
        })()
      : routeContext.requestUrl;
    const linkVariantState = consumeProxyLinkVariantPrefix(normalizedRemainingInput);
    let remaining = linkVariantState.remaining;
    if ((normalizedRemainingInput === "" && !normalizedRequestUrl.pathname.endsWith("/")) || linkVariantState.needsTrailingSlashRedirect === true) {
      return {
        response: RuntimeEntry.buildTrailingSlashRedirectResponse(request, normalizedPathname)
      };
    }
    if (remaining === "") remaining = "/";
    if (playbackHotEligible && !playbackRouteHotSnapshot) {
      playbackRouteHotSnapshot = await Database.primePlaybackRouteHotSnapshot(nodeName, nodeData, env);
    }
    return {
      nodeData,
      nodeName,
      secret: "",
      remaining: sanitizeProxyPath(remaining),
      linkVariant: linkVariantState.linkVariant,
      requestUrl: normalizedRequestUrl,
      pathNormalizationState,
      playbackRouteHotSnapshot,
      targetHotCacheState,
      entryMode: "kv_route",
      routeKindOverride: options.isLegacyHostRequest === true
        ? "legacy_host_prefix_path_compat"
        : "host_prefix_path_compat",
      attachLegacyProxyContext: options.isLegacyHostRequest === true
    };
  },

  async resolveLegacyHostCookieRouteContext(routeContext, env, ctx, request) {
    if (!isLegacyProxyContextFallbackPath(routeContext?.normalizedPathname)) return null;
    const cookieHeader = request.headers.get("Cookie") || "";
    const cookieValue = String(parseCookieHeader(cookieHeader).get(LEGACY_PROXY_CONTEXT_COOKIE_NAME) || "").trim();
    if (!cookieValue) return null;

    const parsedContext = await parseLegacyProxyContextCookieValue(cookieValue, env, {
      requestHost: routeContext.requestHost
    });
    if (parsedContext?.ok !== true) {
      return { response: this.buildLegacyProxyContextNotFoundResponse(routeContext) };
    }

    const nodeName = String(parsedContext.payload?.node || "").trim().toLowerCase();
    if (!nodeName) {
      return { response: this.buildLegacyProxyContextNotFoundResponse(routeContext) };
    }

    const playbackHotEligible = isPlaybackCriticalProxyPath(routeContext.normalizedPathname);
    let playbackRouteHotSnapshot = playbackHotEligible ? await Database.getVerifiedPlaybackRouteHotSnapshot(nodeName, env) : null;
    const targetHotCacheState = playbackHotEligible
      ? (playbackRouteHotSnapshot ? "hit" : "miss")
      : "skip";
    const nodeData = playbackRouteHotSnapshot?.nodeData || await Database.getNode(nodeName, env, ctx);
    if (!nodeData) {
      return { response: this.buildLegacyProxyContextNotFoundResponse(routeContext) };
    }
    const hostPrefixCompat = isHostPrefixEntryMode(nodeData?.entryMode);
    if (playbackHotEligible && !playbackRouteHotSnapshot) {
      playbackRouteHotSnapshot = await Database.primePlaybackRouteHotSnapshot(nodeName, nodeData, env);
    }

    return {
      nodeData,
      nodeName,
      secret: hostPrefixCompat ? "" : nodeData.secret,
      remaining: routeContext.normalizedPathname,
      linkVariant: "main",
      requestUrl: routeContext.requestUrl,
      playbackRouteHotSnapshot,
      targetHotCacheState,
      entryMode: "kv_route",
      routeKindOverride: hostPrefixCompat
        ? "legacy_host_context_cookie_host_prefix_compat"
        : "legacy_host_context_cookie"
    };
  },

  async handleFetch(request, env, ctx) {
    const routeContext = RuntimeEntry.buildFetchRouteContext(request, env);

    if ((request.method === "GET" || request.method === "HEAD") && routeContext.pathnameLower === "/favicon.ico") {
      return renderFaviconResponse(request.method);
    }

    const runtimeConfig = await getRuntimeConfig(env);
    const isLegacyHostRequest = !!(
      routeContext.configuredLegacyHost
      && routeContext.configuredLegacyHost !== routeContext.configuredHost
      && routeContext.requestHostLower
      && routeContext.requestHostLower === routeContext.configuredLegacyHost
    );
    const hostPrefixProxyActive = runtimeConfig.enableHostPrefixProxy === true && !!routeContext.configuredHost && !isLegacyHostRequest;
    routeContext.hostPrefixMatch = hostPrefixProxyActive
      ? resolveHostPrefixMatch(routeContext.requestHost, routeContext.configuredHost)
      : null;
    const isConfiguredHostSubdomain = !!(
      hostPrefixProxyActive
      && routeContext.configuredHost
      && routeContext.requestHostLower
      && routeContext.requestHostLower !== routeContext.configuredHost
      && routeContext.requestHostLower.endsWith(`.${routeContext.configuredHost}`)
    );

    if (routeContext.hostPrefixMatch) {
      const hostPrefixRoute = await RuntimeEntry.resolveHostPrefixProxyRouteContext(routeContext, env, ctx, request);
      if (hostPrefixRoute?.response) return hostPrefixRoute.response;
      if (hostPrefixRoute?.nodeData) {
        return Proxy.handle(request, hostPrefixRoute.nodeData, hostPrefixRoute.remaining, routeContext.hostPrefixMatch.prefix, hostPrefixRoute.secret, env, ctx, {
          requestUrl: hostPrefixRoute.requestUrl || routeContext.requestUrl,
          linkVariant: hostPrefixRoute.linkVariant,
          targetHotCacheState: hostPrefixRoute.targetHotCacheState,
          cachedTargetRecords: Array.isArray(hostPrefixRoute.playbackRouteHotSnapshot?.targetRecords)
            ? hostPrefixRoute.playbackRouteHotSnapshot.targetRecords
            : null,
          entryMode: hostPrefixRoute.entryMode
        });
      }
      return buildEdgeCorsResponse(routeContext.dynamicCors, "Not Found", 404, { mergeOriginVary: true });
    }

    if (isConfiguredHostSubdomain) {
      return buildEdgeCorsResponse(routeContext.dynamicCors, "Not Found", 404, { mergeOriginVary: true });
    }

    if (request.method === "GET" && routeContext.normalizedPathname === "/") {
      return renderLandingPage(env, routeContext.initHealth);
    }

    if ((request.method === "GET" || request.method === "HEAD") && (
      pathnameMatchesExactOrTrailingSlash(routeContext.pathnameLower, routeContext.adminPathLower)
      || pathnameMatchesExactOrTrailingSlash(routeContext.pathnameLower, routeContext.adminLoginPathLower)
    )) {
      return renderAdminPage(request, env, ctx, routeContext.initHealth);
    }

    if (request.method === "OPTIONS" && RuntimeEntry.isAdminPreflightRoute(routeContext)) {
      return buildEdgeCorsResponse(routeContext.dynamicCors, null, 200, { mergeOriginVary: true });
    }

    if (request.method === "POST" && (
      pathnameMatchesExactOrTrailingSlash(routeContext.pathnameLower, routeContext.adminLoginPathLower)
      || RuntimeEntry.isLegacyAdminLoginRoute(routeContext)
    )) {
      return Auth.handleLogin(request, env);
    }

    if (request.method === "POST" && pathnameMatchesExactOrTrailingSlash(routeContext.pathnameLower, routeContext.adminPathLower)) {
      if (!(await Auth.verifyRequest(request, env))) return jsonError("UNAUTHORIZED", "未授权", 401);
      try {
        return await normalizeJsonApiResponse(await Database.handleApi(request, env, ctx));
      } catch (e) {
        const normalizedError = normalizeAppErrorForResponse(e, {
          code: "INTERNAL_ERROR",
          message: "Server Error",
          status: 500
        });
        logRuntimeFailure("admin_api.unhandled_error", e, {
          path: routeContext.pathnameLower,
          method: request.method,
          responseCode: normalizedError.code,
          responseStatus: normalizedError.status
        }, "error");
        return jsonError(
          normalizedError.code,
          normalizedError.message,
          normalizedError.status,
          normalizedError.details
        );
      }
    }

    const hostPrefixCompatRoute = await RuntimeEntry.resolveHostPrefixPathCompatRouteContext(routeContext, env, ctx, request, {
      isLegacyHostRequest
    });
    if (hostPrefixCompatRoute?.response) return hostPrefixCompatRoute.response;
    if (hostPrefixCompatRoute?.nodeData) {
      const hostPrefixCompatResponse = await Proxy.handle(
        request,
        hostPrefixCompatRoute.nodeData,
        hostPrefixCompatRoute.remaining,
        hostPrefixCompatRoute.nodeName,
        hostPrefixCompatRoute.secret,
        env,
        ctx,
        {
          requestUrl: hostPrefixCompatRoute.requestUrl || routeContext.requestUrl,
          linkVariant: hostPrefixCompatRoute.linkVariant,
          pathNormalizationState: hostPrefixCompatRoute.pathNormalizationState,
          targetHotCacheState: hostPrefixCompatRoute.targetHotCacheState,
          cachedTargetRecords: Array.isArray(hostPrefixCompatRoute.playbackRouteHotSnapshot?.targetRecords)
            ? hostPrefixCompatRoute.playbackRouteHotSnapshot.targetRecords
            : null,
          entryMode: hostPrefixCompatRoute.entryMode,
          routeKindOverride: hostPrefixCompatRoute.routeKindOverride
        }
      );
      return hostPrefixCompatRoute.attachLegacyProxyContext === true
        ? await RuntimeEntry.maybeAttachLegacyProxyContextResponse(
          hostPrefixCompatResponse,
          routeContext.requestHost,
          hostPrefixCompatRoute.nodeName,
          env
        )
        : hostPrefixCompatResponse;
    }

    const proxyRoute = await RuntimeEntry.resolveProxyRouteContext(routeContext, env, ctx, request);
    if (proxyRoute?.response) return proxyRoute.response;
    if (proxyRoute?.nodeData) {
      const proxyResponse = await Proxy.handle(request, proxyRoute.nodeData, proxyRoute.remaining, routeContext.root, proxyRoute.secret, env, ctx, {
        requestUrl: proxyRoute.requestUrl || routeContext.requestUrl,
        linkVariant: proxyRoute.linkVariant,
        pathNormalizationState: proxyRoute.pathNormalizationState,
        targetHotCacheState: proxyRoute.targetHotCacheState,
        cachedTargetRecords: Array.isArray(proxyRoute.playbackRouteHotSnapshot?.targetRecords)
          ? proxyRoute.playbackRouteHotSnapshot.targetRecords
          : null,
        entryMode: proxyRoute.entryMode
      });
      return isLegacyHostRequest
        ? await RuntimeEntry.maybeAttachLegacyProxyContextResponse(proxyResponse, routeContext.requestHost, routeContext.root, env)
        : proxyResponse;
    }

    if (isLegacyHostRequest && isLegacyProxyContextFallbackPath(routeContext.normalizedPathname)) {
      const legacyCookieRoute = await RuntimeEntry.resolveLegacyHostCookieRouteContext(routeContext, env, ctx, request);
      if (legacyCookieRoute?.response) return legacyCookieRoute.response;
      if (legacyCookieRoute?.nodeData) {
        const legacyCookieResponse = await Proxy.handle(
          request,
          legacyCookieRoute.nodeData,
          legacyCookieRoute.remaining,
          legacyCookieRoute.nodeName,
          legacyCookieRoute.secret,
          env,
          ctx,
          {
            requestUrl: legacyCookieRoute.requestUrl || routeContext.requestUrl,
            linkVariant: legacyCookieRoute.linkVariant,
            targetHotCacheState: legacyCookieRoute.targetHotCacheState,
            cachedTargetRecords: Array.isArray(legacyCookieRoute.playbackRouteHotSnapshot?.targetRecords)
              ? legacyCookieRoute.playbackRouteHotSnapshot.targetRecords
              : null,
            entryMode: legacyCookieRoute.entryMode,
            routeKindOverride: legacyCookieRoute.routeKindOverride
          }
        );
        return RuntimeEntry.maybeAttachLegacyProxyContextResponse(
          legacyCookieResponse,
          routeContext.requestHost,
          legacyCookieRoute.nodeName,
          env
        );
      }
    }

    return buildEdgeCorsResponse(routeContext.dynamicCors, "Not Found", 404, { mergeOriginVary: true });
  }
};

const RuntimeSchedule = {
  getStatusSection(status = {}, ...keys) {
    for (const key of keys) {
      if (!key) continue;
      const section = status?.[key];
      if (isPlainObject(section)) return section;
    }
    return {};
  },

  markPartialFailure(status = "success") {
    return status === "success" ? "partial_failure" : status;
  },

  getPendingDueAt(pendingItems = []) {
    return String(pendingItems[0]?.dueAt || "");
  },

  normalizeFixedQueueState(fixedQueue = {}, localDateKey = "") {
    const nextLocalDateKey = String(localDateKey || fixedQueue?.localDateKey || "");
    return nextLocalDateKey
      ? {
          ...fixedQueue,
          localDateKey: nextLocalDateKey,
          executedSlots: normalizeScheduleClockTimeList(fixedQueue?.executedSlots || [], [])
        }
      : {
          ...fixedQueue,
          executedSlots: normalizeScheduleClockTimeList(fixedQueue?.executedSlots || [], [])
        };
  },

  appendFixedQueueSlot(fixedQueue = {}, localDateKey = "", clockTime = "") {
    return RuntimeSchedule.normalizeFixedQueueState({
      ...fixedQueue,
      executedSlots: [...(fixedQueue?.executedSlots || []), clockTime]
    }, localDateKey);
  },

  buildClockProcessedMeta(localDateKey = "", processedSlots = []) {
    const lastSuccessSlot = processedSlots[processedSlots.length - 1] || "";
    return {
      processedSlots,
      lastPlannedSlot: lastSuccessSlot ? `${localDateKey} ${lastSuccessSlot}` : "",
      reason: processedSlots.length > 1 ? "clock_slots_processed" : "clock_slot_processed"
    };
  },

  buildSkippedState(baseState = {}, skippedAt = "", reason = "", extra = {}) {
    return {
      ...baseState,
      status: "skipped",
      lastSkippedAt: skippedAt,
      reason,
      ...extra
    };
  },

  buildPendingState(baseState = {}, reason = "", extra = {}) {
    return {
      ...baseState,
      status: "pending",
      reason,
      ...extra
    };
  },

  buildSuccessState(baseState = {}, successAt = "", extra = {}) {
    return {
      ...baseState,
      status: "success",
      lastSuccessAt: successAt,
      ...extra
    };
  },

  buildFailedState(baseState = {}, failedAt = "", error = "", extra = {}) {
    return {
      ...baseState,
      status: "failed",
      lastErrorAt: failedAt,
      lastError: error,
      ...extra
    };
  },

  buildStateFromResult(baseState = {}, result = {}, options = {}) {
    const safeResult = isPlainObject(result) ? result : {};
    const extra = isPlainObject(options.extra) ? options.extra : {};
    if (safeResult.status === "success") {
      return RuntimeSchedule.buildSuccessState(
        baseState,
        String(safeResult.lastSuccessAt || options.at || "").trim(),
        {
          ...safeResult,
          ...extra
        }
      );
    }
    if (safeResult.status === "failed") {
      return RuntimeSchedule.buildFailedState(
        baseState,
        String(safeResult.lastErrorAt || options.at || "").trim(),
        String(safeResult.lastError || options.error || "").trim(),
        {
          ...safeResult,
          ...extra
        }
      );
    }
    return RuntimeSchedule.buildSkippedState(
      baseState,
      String(safeResult.lastSkippedAt || options.at || "").trim(),
      String(safeResult.reason || options.defaultReason || "").trim(),
      {
        ...safeResult,
        ...extra
      }
    );
  },

  createNonCriticalRunner(leaseToken = "") {
    return async (promise, scope, context = null, fallbackValue = null) => withNonCriticalFallback(
      promise,
      `scheduled.${scope}`,
      {
        leaseToken,
        ...(isPlainObject(context) ? context : {})
      },
      fallbackValue
    );
  },

  buildBusyStatusPatch(scheduledNowIso, lease, reason) {
    return {
      scheduled: {
        lastSkippedAt: scheduledNowIso,
        lastSkipReason: reason,
        lock: {
          status: "busy",
          reason,
          expiresAt: lease.lock?.expiresAt || null,
          backend: String(lease?.backend || lease?.lock?.backend || "").trim() || "d1"
        }
      }
    };
  },

  buildSkippedStatusPatch(scheduledNowIso, reason, backend = "d1") {
    const safeReason = String(reason || "scheduled_skipped").trim() || "scheduled_skipped";
    return {
      scheduled: {
        status: "skipped",
        lastSkippedAt: scheduledNowIso,
        lastSkipReason: safeReason,
        lastFinishedAt: scheduledNowIso,
        lock: {
          status: "skipped",
          reason: safeReason,
          backend: String(backend || "").trim() || "d1"
        }
      }
    };
  },

  buildRunningStatusPatch(startedAt, leaseToken, leaseState, scheduledLeaseMs) {
    return {
      scheduled: {
        status: "running",
        lastStartedAt: startedAt,
        lock: {
          status: "held",
          token: leaseToken,
          expiresAt: leaseState.lock?.expiresAt || (nowMs() + scheduledLeaseMs)
        }
      }
    };
  },

  buildFinalLockState(leaseState, finishedAt, released) {
    if (leaseState.lostReason) {
      return {
        status: "lost",
        reason: leaseState.lostReason,
        lastCheckedAt: finishedAt
      };
    }
    return {
      status: released ? "released" : "release_skipped",
      releasedAt: finishedAt
    };
  },

  createLeaseController({ leaseStores, leaseToken, scheduledLeaseMs, leaseBackend = "", initialLock = null }) {
    const leaseState = {
      active: true,
      lostReason: null,
      lock: initialLock
    };
    const renew = async () => {
      if (!leaseState.active) return null;
      const renewed = await Database.renewScheduledLease(leaseStores, leaseToken, scheduledLeaseMs, { backend: leaseBackend });
      if (!renewed) {
        leaseState.active = false;
        leaseState.lostReason = leaseState.lostReason || "lease_lost";
        return null;
      }
      leaseState.lock = renewed;
      return renewed;
    };
    const ensureActive = async () => {
      if (!leaseState.active) throw new Error(leaseState.lostReason || "scheduled_lease_lost");
      const renewed = await renew();
      if (!renewed) throw new Error(leaseState.lostReason || "scheduled_lease_lost");
      return renewed;
    };
    const refreshIntervalMs = Math.max(5000, Math.min(Math.floor(scheduledLeaseMs / 3), 60000));
    const keepalivePromise = (async () => {
      while (leaseState.active) {
        let remainingMs = refreshIntervalMs;
        while (leaseState.active && remainingMs > 0) {
          const sliceMs = Math.min(remainingMs, 1000);
          await sleepMs(sliceMs);
          remainingMs -= sliceMs;
        }
        if (!leaseState.active) break;
        await renew();
      }
    })().catch(error => {
      leaseState.active = false;
      leaseState.lostReason = leaseState.lostReason || "lease_renew_failed";
      logRuntimeFailure("scheduled.lease_keepalive", error, {
        leaseToken,
        backend: leaseBackend || "unknown",
        lostReason: leaseState.lostReason
      });
    });
    return {
      leaseState,
      ensureActive,
      keepalivePromise
    };
  }
};

const TEST_RUNTIME_GLOBAL = /** @type {{ process?: { versions?: { node?: unknown } } }} */ (globalThis);
const IS_NODE_LIKE_TEST_RUNTIME = !!TEST_RUNTIME_GLOBAL.process?.versions?.node;
if (IS_NODE_LIKE_TEST_RUNTIME) {
  globalThis.__EMBY_PROXY_NODE_TEST_HOOKS__ = Object.freeze({
    Config,
    GLOBALS,
    Database,
    Proxy,
    createTargetRecord,
    isTargetRecord,
    buildUpstreamProxyUrl,
    buildFastSegmentUpstreamUrlText,
    shouldUseSegmentFastUpstreamBuilder
  });
}

export default {
  async fetch(request, env, ctx) {
    return RuntimeEntry.handleFetch(request, env, ctx);
  },

  async scheduled(event, env, ctx) {
    ctx.waitUntil((async () => {
      const db = Database.getDB(env);
      const kv = Database.getKV(env);
      if (!kv && !db) return;
      const scheduledLeaseStore = { db };
      const runtimeConfig = await getRuntimeConfig(env);
      const scheduleUtcOffsetMinutes = normalizeScheduleUtcOffsetMinutes(runtimeConfig?.scheduleUtcOffsetMinutes);
      const scheduledNow = event?.scheduledTime !== undefined ? new Date(event.scheduledTime) : new Date();
      const scheduledNowIso = buildScheduleLocalIso(scheduledNow, scheduleUtcOffsetMinutes);
      const makeScheduledIso = (value = new Date()) => buildScheduleLocalIso(value, scheduleUtcOffsetMinutes);
      const scheduledLeaseMs = clampIntegerConfig(runtimeConfig?.scheduledLeaseMs, Config.Defaults.ScheduledLeaseMs, Config.Defaults.ScheduledLeaseMinMs, 15 * 60 * 1000);
      const leaseToken = `${nowMs()}-${Math.random().toString(36).slice(2, 10)}`;
      const scheduledNonCritical = RuntimeSchedule.createNonCriticalRunner(leaseToken);
      const patchScheduledSkip = async (reason) => {
        const safeReason = String(reason || "db_unavailable").trim() || "db_unavailable";
        await scheduledNonCritical(
          Database.patchOpsStatus(env, RuntimeSchedule.buildSkippedStatusPatch(scheduledNowIso, safeReason, "d1")),
          "patch_skipped_status",
          { reason: safeReason, backend: "d1" },
          null
        );
      };
      if (!db) {
        await patchScheduledSkip("db_not_configured");
        return;
      }
      const lease = await Database.tryAcquireScheduledLeaseWithDb(db, { token: leaseToken, leaseMs: scheduledLeaseMs });
      if (!lease.acquired) {
        const leaseBusyReason = String(lease.reason || "lease_not_acquired");
        if (leaseBusyReason === "db_not_configured" || leaseBusyReason === "db_unavailable" || leaseBusyReason === "db_init_failed") {
          await patchScheduledSkip(leaseBusyReason);
          return;
        }
        await scheduledNonCritical(
          Database.patchOpsStatus(env, RuntimeSchedule.buildBusyStatusPatch(scheduledNowIso, lease, leaseBusyReason)),
          "patch_busy_status",
          { reason: leaseBusyReason },
          null
        );
        return;
      }
      const leaseBackend = String(lease.backend || lease.lock?.backend || "").trim().toLowerCase();
      const leaseController = RuntimeSchedule.createLeaseController({
        leaseStores: scheduledLeaseStore,
        leaseToken,
        scheduledLeaseMs,
        leaseBackend,
        initialLock: lease.lock || null
      });
      const { leaseState, ensureActive: ensureLeaseActive, keepalivePromise: leaseKeepalive } = leaseController;

      const startedAt = scheduledNowIso;
      await scheduledNonCritical(
        Database.patchOpsStatus(env, RuntimeSchedule.buildRunningStatusPatch(startedAt, leaseToken, leaseState, scheduledLeaseMs)),
        "patch_running_status",
        { startedAt },
        null
      );

      const scheduledState = {
        status: "success",
        lastStartedAt: startedAt,
        lastFinishedAt: null,
        lastSuccessAt: null,
        lastErrorAt: null,
        lastError: null,
        d1Tidy: {},
        cleanup: {},
        kvTidy: {},
        tgDailyReport: {},
        alerts: {}
      };
      const nowIso = () => makeScheduledIso(new Date());

      try {
        const config = runtimeConfig || {};
        const previousScheduledStatus = await scheduledNonCritical(
          Database.getOpsStatusSection(env, "scheduled"),
          "read_previous_status",
          null,
          {}
        );

        if (db) {
          try {
            await ensureLeaseActive();
            const dayWindow = buildOffsetDayWindow(scheduledNow, config.scheduleUtcOffsetMinutes);
            const statsBucketDate = dayWindow.dateKey;
            const statsStartTs = dayWindow.startTs;
            const statsEndTs = dayWindow.endTs;
            const statsUtcOffsetMinutes = normalizeScheduleUtcOffsetMinutes(config.scheduleUtcOffsetMinutes);
            const previousCleanupStatus = Database.getPreviousD1TidyState(previousScheduledStatus);
            const d1Plan = await Database.buildD1TidyPlan(env, {
              db,
              kv,
              config,
              mode: "scheduled",
              maintenanceMode: "smart",
              previousScheduledState: previousScheduledStatus,
              previousCleanupStatus,
              scheduledNow,
              dayWindow,
              statsBucketDate,
              statsStartTs,
              statsEndTs,
              statsUtcOffsetMinutes
            });
            const d1Result = await Database.applyD1TidyPlan(d1Plan, {
              env,
              db,
              kv,
              ctx,
              mode: "scheduled",
              maintenanceMode: "smart",
              beforeEachStep: ensureLeaseActive
            });
            const d1FinishedAt = nowIso();
            const d1StatusPayload = Database.buildD1TidyStatusPayload(d1Result.summary, {
              mode: "scheduled",
              maintenanceMode: "smart",
              triggeredBy: "scheduled",
              timestamp: d1FinishedAt
            });
            scheduledState.d1Tidy = d1StatusPayload.d1Tidy;
            scheduledState.cleanup = d1StatusPayload.cleanup;
            if (scheduledState.d1Tidy.status === "partial_failure" || scheduledState.d1Tidy.status === "failed") {
              scheduledState.status = "partial_failure";
            }
            await ensureLeaseActive();
          } catch (dbErr) {
            scheduledState.status = "partial_failure";
            const failedStatusPayload = Database.buildD1TidyStatusPayload({
              status: "failed",
              lastError: dbErr?.message || String(dbErr),
              maintenanceMode: "smart"
            }, {
              mode: "scheduled",
              maintenanceMode: "smart",
              triggeredBy: "scheduled",
              timestamp: nowIso()
            });
            scheduledState.d1Tidy = failedStatusPayload.d1Tidy;
            scheduledState.cleanup = failedStatusPayload.cleanup;
            console.error("Scheduled DB Cleanup Error: ", dbErr);
          }
        } else {
          const skippedStatusPayload = Database.buildD1TidyStatusPayload({
            status: "skipped",
            reason: "db_not_configured",
            maintenanceMode: "smart"
          }, {
            mode: "scheduled",
            maintenanceMode: "smart",
            triggeredBy: "scheduled",
            timestamp: nowIso()
          });
          scheduledState.d1Tidy = skippedStatusPayload.d1Tidy;
          scheduledState.cleanup = skippedStatusPayload.cleanup;
        }

        const previousKvTidyState = RuntimeSchedule.getStatusSection(previousScheduledStatus, "kvTidy");
        scheduledState.kvTidy = {
          ...previousKvTidyState,
          mode: "manual_only",
          lastAutoSkipAt: nowIso(),
          autoSkipReason: "manual_only"
        };

        const { tgBotToken, tgChatId } = config;
        const previousTgDailyReportState = RuntimeSchedule.getStatusSection(previousScheduledStatus, "tgDailyReport", "report");
        const previousAlertsState = RuntimeSchedule.getStatusSection(previousScheduledStatus, "alerts");
        const tgDailyReportClockTimes = normalizeScheduleClockTimeList(config.tgDailyReportClockTimes, Config.Defaults.TgDailyReportClockTimes);

        const dailyReportDueState = getDueScheduledClockSlots(previousTgDailyReportState, tgDailyReportClockTimes, scheduleUtcOffsetMinutes, scheduledNow);
        const selectedDailyReportKinds = resolveDailyTelegramReportKinds(config, config);
        const baseDailyReportState = {
          ...previousTgDailyReportState,
          clockTimes: tgDailyReportClockTimes,
          reportKinds: selectedDailyReportKinds
        };
        if (config.tgDailyReportEnabled === true) {
          let nextReportFixedQueue = RuntimeSchedule.normalizeFixedQueueState(dailyReportDueState.fixedQueue);
          if (!selectedDailyReportKinds.length) {
            scheduledState.tgDailyReport = RuntimeSchedule.buildSkippedState(
              baseDailyReportState,
              nowIso(),
              "report_kinds_disabled",
              { fixedQueue: nextReportFixedQueue }
            );
          } else if (!tgBotToken || !tgChatId) {
            scheduledState.tgDailyReport = RuntimeSchedule.buildSkippedState(
              baseDailyReportState,
              nowIso(),
              "telegram_not_configured",
              { fixedQueue: nextReportFixedQueue }
            );
          } else if (dailyReportDueState.due !== true) {
            scheduledState.tgDailyReport = RuntimeSchedule.buildSkippedState(
              baseDailyReportState,
              nowIso(),
              dailyReportDueState.reason || "time_not_matched",
              { fixedQueue: nextReportFixedQueue }
            );
          } else {
            let processedSlots = [];
            let reportFailed = null;
            let totalSentCount = 0;
            for (const clockTime of dailyReportDueState.dueSlots) {
              try {
                await ensureLeaseActive();
                const reportResult = await Database.sendDailyTelegramReport(env, {
                  now: scheduledNow,
                  reportKinds: selectedDailyReportKinds
                });
                totalSentCount += Number(reportResult?.sentCount) || 0;
                processedSlots.push(clockTime);
                nextReportFixedQueue = RuntimeSchedule.appendFixedQueueSlot(nextReportFixedQueue, dailyReportDueState.context.dateKey, clockTime);
              } catch (reportErr) {
                reportFailed = reportErr;
                console.error("Scheduled Daily Report Error: ", reportErr);
                break;
              }
            }
            if (!reportFailed) {
              scheduledState.tgDailyReport = RuntimeSchedule.buildSuccessState(
                baseDailyReportState,
                nowIso(),
                {
                  fixedQueue: nextReportFixedQueue,
                  sentCount: totalSentCount,
                  ...RuntimeSchedule.buildClockProcessedMeta(dailyReportDueState.context.dateKey, processedSlots)
                }
              );
            } else {
              scheduledState.status = RuntimeSchedule.markPartialFailure(scheduledState.status);
              scheduledState.tgDailyReport = RuntimeSchedule.buildFailedState(
                baseDailyReportState,
                nowIso(),
                reportFailed?.message || String(reportFailed),
                {
                  fixedQueue: nextReportFixedQueue,
                  processedSlots
                }
              );
            }
          }
        } else {
          scheduledState.tgDailyReport = RuntimeSchedule.buildSkippedState(
            baseDailyReportState,
            nowIso(),
            "disabled",
            { fixedQueue: dailyReportDueState.fixedQueue }
          );
        }

        try {
          await ensureLeaseActive();
          const alertResult = await Database.maybeSendRuntimeAlerts(env, scheduledState);
          const alertStatus = alertResult.sent === true ? "success" : "skipped";
          const alertPolledAt = nowIso();
          scheduledState.alerts = alertResult.sent === true
            ? RuntimeSchedule.buildSuccessState(
                previousAlertsState,
                alertPolledAt,
                {
                  lastPolledAt: alertPolledAt,
                  lastSkippedAt: previousAlertsState.lastSkippedAt || "",
                  issueCount: Number(alertResult.issueCount) || 0,
                  reason: alertResult.reason || "alert_sent"
                }
              )
            : RuntimeSchedule.buildSkippedState(
                previousAlertsState,
                alertPolledAt,
                alertResult.reason || "no_alerts",
                {
                  lastPolledAt: alertPolledAt,
                  lastSuccessAt: previousAlertsState.lastSuccessAt || "",
                  issueCount: Number(alertResult.issueCount) || 0
                }
              );
        } catch (alertErr) {
          scheduledState.status = RuntimeSchedule.markPartialFailure(scheduledState.status);
          const alertFailedAt = nowIso();
          scheduledState.alerts = RuntimeSchedule.buildFailedState(
            previousAlertsState,
            alertFailedAt,
            alertErr?.message || String(alertErr),
            { lastPolledAt: alertFailedAt }
          );
          console.error("Scheduled Alert Error: ", alertErr);
        }
      } catch (err) {
          scheduledState.status = "failed";
          scheduledState.lastErrorAt = nowIso();
          scheduledState.lastError = err?.message || String(err);
          console.error("Scheduled Task Error: ", err);
      } finally {
        leaseState.active = false;
        await leaseKeepalive;
        const finishedAt = nowIso();
        scheduledState.lastFinishedAt = finishedAt;
        if (scheduledState.status === "success") scheduledState.lastSuccessAt = finishedAt;
        const released = leaseState.lostReason
          ? false
          : await scheduledNonCritical(
            Database.releaseScheduledLease(scheduledLeaseStore, leaseToken, { backend: leaseBackend }),
            "release_lease",
            { backend: leaseBackend },
            false
          );
        scheduledState.lock = RuntimeSchedule.buildFinalLockState(leaseState, finishedAt, released);
          await scheduledNonCritical(
            Database.patchOpsStatus(env, { scheduled: scheduledState }),
            "patch_final_status",
            {
              finishedAt,
              finalStatus: scheduledState.status,
              leaseLostReason: leaseState.lostReason || ""
            },
            null
          );
      }
    })());
  }
};
